/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Features:
 * - JSON payload formatting per notification type
 * - URL validation
 * - Configurable HTTP headers and timeout
 * - In-memory delivery log for testing
 *
 * Implements NotificationAdapter so the NotificationService can
 * route webhook-channel notifications here.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface WebhookConfig {
  /** The URL to POST webhook payloads to. */
  url: string;
  /** Optional secret used to sign payloads (included as X-Webhook-Secret header). */
  secret?: string;
  /** Request timeout in milliseconds. */
  timeoutMs: number;
  /** Additional headers to include in the request. */
  headers?: Record<string, string>;
}

const defaultWebhookConfig: WebhookConfig = {
  url: 'https://example.com/webhook',
  timeoutMs: 5000,
};

/**
 * The JSON structure sent in the webhook POST body.
 */
export interface WebhookDelivery {
  url: string;
  payload: WebhookPayloadBody;
  headers: Record<string, string>;
  deliveredAt: Date;
}

export interface WebhookPayloadBody {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/** Basic URL validation — must start with http:// or https://. */
function isValidUrl(url: string): boolean {
  return /^https?:\/\/.+/.test(url);
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private deliveries: WebhookDelivery[] = [];

  constructor(private config: WebhookConfig = defaultWebhookConfig) {}

  /**
   * Format the notification payload into the JSON body for the webhook.
   */
  formatPayload(payload: NotificationPayload): WebhookPayloadBody {
    return {
      event: payload.notificationType,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Resolve and validate the webhook URL.
   * Returns the validated URL or null if invalid.
   */
  resolveUrl(): string | null {
    const url = this.config.url.trim();
    if (!url || !isValidUrl(url)) {
      this.logger.warn(`Invalid webhook URL: "${this.config.url}"`);
      return null;
    }
    return url;
  }

  /**
   * Build the HTTP headers for the webhook request.
   */
  buildHeaders(): Record<string, string> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      ...this.config.headers,
    };

    if (this.config.secret) {
      headers['X-Webhook-Secret'] = this.config.secret;
    }

    return headers;
  }

  /**
   * Send a webhook notification.
   *
   * 1. Validates the webhook URL.
   * 2. Formats the payload as JSON.
   * 3. Records the delivery (in-memory for testing; swap for real HTTP in production).
   */
  async send(payload: NotificationPayload): Promise<boolean> {
    try {
      const url = this.resolveUrl();
      if (!url) {
        return false;
      }

      const webhookBody = this.formatPayload(payload);
      const headers = this.buildHeaders();

      this.logger.info(`Sending webhook to ${url}: ${payload.subject}`);

      this.deliveries.push({
        url,
        payload: webhookBody,
        headers,
        deliveredAt: new Date(),
      });

      return true;
    } catch (error) {
      this.logger.error(
        `Failed to send webhook to ${this.config.url}: ${error instanceof Error ? error.message : String(error)}`,
      );
      return false;
    }
  }

  /**
   * Get all webhook deliveries through this adapter (for testing).
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Clear delivery history (for testing).
   */
  clearDeliveries(): void {
    this.deliveries = [];
  }
}

